import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  TextField,
  Button,
  Typography,
  Link,
  Alert,
  CircularProgress,
  Container,
  InputAdornment,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Grid,
  Card,
  CardContent,
  Chip
} from '@mui/material';
import {
  Visibility,
  VisibilityOff,
  Email,
  Lock,
  Instagram,
  YouTube,
  Telegram as TelegramIcon,
  Close,
  Payment,
  Subscriptions,
  AccountBalance,
  ShoppingCart
} from '@mui/icons-material';
import { Link as RouterLink } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../../contexts/AuthContext';
import CryptoBackground from './CryptoBackground';

const Login = () => {
  const { login } = useAuth();
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [showInviteModal, setShowInviteModal] = useState(false);
  const [inviteCode, setInviteCode] = useState('');
  const [inviteError, setInviteError] = useState('');
  const [inviteSuccess, setInviteSuccess] = useState(false);

  // Opções de pagamento
  const paymentOptions = {
    subscription: {
      title: "🚀 Assinar Nautilus",
      price: "R$ 299,99/mês",
      link: "https://pay.hub.la/tmF5YtOlGb1GDVFSam7S",
      color: "success"
    },
    recharge: [
      { value: 'R$ 9,00', link: 'https://pay.hub.la/ekfJp2uXQ0S5ZBb65Otb', isTest: true, desc: '(Teste)' },
      { value: 'R$ 50,00', link: 'https://pay.hub.la/MdORdaFcTzWvhT9IkZHP', desc: '' },
      { value: 'R$ 100,00', link: 'https://pay.hub.la/mFfwQbUAqILTw8bfDXjo', desc: '' },
      { value: 'R$ 200,00', link: 'https://pay.hub.la/EVrxnuDyf4JeB0uIYaFC', desc: '' },
      { value: 'R$ 500,00', link: 'https://pay.hub.la/LmFhy6R6HP3fjoJxZe5z', desc: '' }
    ]
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      await login(formData.email, formData.password);
      toast.success('Login realizado com sucesso!');
    } catch (error) {
      // Filtrar erros de verificação de sessão para não confundir o usuário
      if (error.message && error.message.includes('verificação de sessão')) {
        console.log('Erro de verificação de sessão ignorado:', error.message);
        return;
      }

      const errorMessage = error.response?.data?.message || error.message || 'Erro ao fazer login. Verifique suas credenciais.';
      setError(errorMessage);
      toast.error(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const togglePasswordVisibility = () => {
    setShowPassword(!showPassword);
  };

  const handleOpenPaymentModal = () => {
    setShowPaymentModal(true);
  };

  const handleClosePaymentModal = () => {
    setShowPaymentModal(false);
  };

  const handlePaymentClick = (link) => {
    window.open(link, '_blank', 'noopener,noreferrer');
  };

  const handleOpenInviteModal = () => setShowInviteModal(true);
  const handleCloseInviteModal = () => setShowInviteModal(false);

  const handleValidateInvite = () => {
    if (inviteCode.trim() === 'Bigwhale81#') {
      setInviteSuccess(true);
      setInviteError('');
    } else {
      setInviteError('Código de convite inválido.');
      setInviteSuccess(false);
    }
  };

  const handleGoToRegister = () => {
    window.location.href = '/register';
  };

  // 3. Função para redirecionar para registro (ajuste: redirecionar automaticamente ao validar)
  useEffect(() => {
    if (inviteSuccess) {
      setShowInviteModal(false);
      setTimeout(() => {
        setInviteCode('');
        setInviteError('');
        setInviteSuccess(false);
        window.location.href = '/register';
      }, 200);
    }
  }, [inviteSuccess]);

  return (
    <Box
      sx={{
        minHeight: '100vh',
        position: 'relative',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: 2,
        background: 'radial-gradient(ellipse at center, rgba(15, 20, 25, 0.3) 0%, rgba(10, 14, 19, 0.2) 50%, rgba(5, 8, 16, 0.1) 100%)',
      }}
    >
      <Container maxWidth="sm" sx={{ position: 'relative', zIndex: 10 }}>
        <Paper
          elevation={24}
          sx={{
            p: 4,
            background: 'rgba(13, 13, 14, 0.3)',
            backdropFilter: 'blur(10px) saturate(180%)',
            border: '1px solid rgba(0, 255, 100, 0.1)',
            borderRadius: 3,
            boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.8), 0 0 0 1px rgba(0, 255, 100, 0.05)',
            position: 'relative',
            overflow: 'hidden',
            '&::before': {
              content: '""',
              position: 'absolute',
              top: 0,
              left: 0,
              right: 0,
              height: '1px',
              background: 'linear-gradient(90deg, transparent, rgba(0, 255, 100, 0.5), transparent)'
            }
          }}
        >
          {/* Logo e Título */}
          <Box sx={{ textAlign: 'center', mb: 4 }}>
            <Typography
              variant="h3"
              component="h1"
              sx={{
                fontWeight: 700,
                mb: 1,
                background: 'linear-gradient(135deg, #00ff64 0%, #00d4ff 100%)',
                backgroundClip: 'text',
                WebkitBackgroundClip: 'text',
                WebkitTextFillColor: 'transparent',
                textShadow: '0 0 30px rgba(0, 255, 100, 0.3)',
                fontSize: { xs: '2rem', sm: '2.5rem' }
              }}
            >
              Nautilus
            </Typography>
            <Typography
              variant="h6"
              sx={{
                color: 'rgba(255, 255, 255, 0.7)',
                fontWeight: 300,
                letterSpacing: '0.5px'
              }}
            >
              Automação Inteligente
            </Typography>
          </Box>

          {/* Formulário de Login */}
          <Box component="form" onSubmit={handleSubmit} sx={{ mb: 4 }}>
            {error && (
              <Alert
                severity="error"
                sx={{
                  mb: 3,
                  backgroundColor: 'rgba(255, 100, 100, 0.1)',
                  border: '1px solid rgba(255, 100, 100, 0.3)',
                  color: '#ff6464',
                  '& .MuiAlert-icon': {
                    color: '#ff6464'
                  }
                }}
              >
                {error}
              </Alert>
            )}

            <TextField
              name="email"
              type="email"
              label="Email"
              value={formData.email}
              onChange={handleChange}
              required
              fullWidth
              margin="normal"
              InputProps={{
                sx: {
                  '& .MuiOutlinedInput-notchedOutline': {
                    borderColor: '#C0C0C0',
                  },
                  '&:hover .MuiOutlinedInput-notchedOutline': {
                    borderColor: '#C0C0C0',
                  },
                  '&.Mui-focused .MuiOutlinedInput-notchedOutline': {
                    borderColor: '#C0C0C0',
                  },
                  color: '#C0C0C0',
                  background: 'rgba(0,0,0,0.3)',
                },
                startAdornment: (
                  <InputAdornment position="start">
                    <Email sx={{ color: '#C0C0C0' }} />
                  </InputAdornment>
                ),
              }}
              sx={{
                '& .MuiInputLabel-root': {
                  color: 'rgba(255, 255, 255, 0.7)',
                },
                '& .MuiInputBase-input': {
                  color: 'white',
                },
              }}
            />

            <TextField
              name="password"
              type={showPassword ? 'text' : 'password'}
              label="Senha"
              value={formData.password}
              onChange={handleChange}
              required
              fullWidth
              margin="normal"
              InputProps={{
                sx: {
                  '& .MuiOutlinedInput-notchedOutline': {
                    borderColor: '#C0C0C0',
                  },
                  '&:hover .MuiOutlinedInput-notchedOutline': {
                    borderColor: '#C0C0C0',
                  },
                  '&.Mui-focused .MuiOutlinedInput-notchedOutline': {
                    borderColor: '#C0C0C0',
                  },
                  color: '#C0C0C0',
                  background: 'rgba(0,0,0,0.3)',
                },
                startAdornment: (
                  <InputAdornment position="start">
                    <Lock sx={{ color: '#C0C0C0' }} />
                  </InputAdornment>
                ),
                endAdornment: (
                  <InputAdornment position="end">
                    <IconButton
                      onClick={togglePasswordVisibility}
                      edge="end"
                      sx={{ color: 'rgba(255, 255, 255, 0.7)' }}
                    >
                      {showPassword ? <VisibilityOff /> : <Visibility />}
                    </IconButton>
                  </InputAdornment>
                ),
              }}
              sx={{
                '& .MuiInputLabel-root': {
                  color: 'rgba(255, 255, 255, 0.7)',
                },
                '& .MuiInputBase-input': {
                  color: 'white',
                },
              }}
            />

            <Button
              type="submit"
              fullWidth
              variant="contained"
              sx={{
                mt: 3,
                mb: 2,
                background: 'rgba(0,0,0,0.3)',
                color: '#C0C0C0',
                border: '2px solid #C0C0C0',
                fontWeight: 700,
                fontSize: '1.1rem',
                borderRadius: 2,
                boxShadow: 'none',
                '&:hover': {
                  background: 'rgba(0,0,0,0.88)',
                  color: '#fff',
                  borderColor: '#C0C0C0',
                },
              }}
            >
              {loading ? (
                <>
                  <CircularProgress size={20} sx={{ mr: 1, color: 'inherit' }} />
                  Entrando...
                </>
              ) : (
                'Entrar'
              )}
            </Button>
          </Box>

          {/* Seção de Registro */}
          <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', mt: 4 }}>
            <Typography variant="h6" sx={{ color: 'white', mb: 2, fontWeight: 500 }}>
              Escolha seu Plano
            </Typography>
            <Box sx={{ display: 'flex', flexDirection: 'row', gap: 3, alignItems: 'flex-end', justifyContent: 'center', mt: 3 }}>
              <Button
                variant="contained"
                onClick={handleOpenPaymentModal}
                className="button-assinatura"
              >
                Assinatura
              </Button>
              <Button
                variant="contained"
                onClick={handleOpenInviteModal}
                className="button-convite"
              >
                Convite
              </Button>
              <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', minWidth: 80 }}>
                <Typography
                  variant="caption"
                  sx={{
                    color: 'rgba(255,255,255,0.6)',
                    fontStyle: 'italic',
                    transform: 'rotate(-18deg)',
                    mb: 0.5,
                    fontWeight: 400
                  }}
                >
                  Em Breve
                </Typography>
                <Button
                  variant="outlined"
                  disabled
                  sx={{
                    color: '#C0C0C0',
                    borderColor: '#C0C0C0',
                    background: 'hsla(0, 0.00%, 0.00%, 0.93)',
                    fontWeight: 500,
                    px: 3,
                    borderRadius: 2,
                    textTransform: 'none',
                    fontSize: '1.1rem',
                    opacity: 0.7,
                    cursor: 'not-allowed',
                    boxShadow: 'none',
                    mt: 0
                  }}
                >
                  Recarregar
                </Button>
              </Box>
            </Box>
          </Box>

          {/* Links Sociais */}
          <Box sx={{ textAlign: 'center', pt: 3, borderTop: '1px solid rgba(255, 255, 255, 0.1)' }}>
            <Typography variant="body2" sx={{ color: 'rgba(255, 255, 255, 0.6)', mb: 2 }}>
              Siga-nos nas redes sociais
            </Typography>
            <Box sx={{ display: 'flex', justifyContent: 'center', gap: 2 }}>
              <IconButton
                href="https://instagram.com/nautilus.automacao"
                target="_blank"
                rel="noopener noreferrer"
                sx={{
                  color: 'rgba(255, 255, 255, 0.6)',
                  '&:hover': {
                    color: '#E4405F',
                    transform: 'translateY(-2px)',
                  },
                  transition: 'all 0.3s ease',
                }}
              >
                <Instagram />
              </IconButton>
              <IconButton
                href="https://youtube.com/@nautilus.automacao"
                target="_blank"
                rel="noopener noreferrer"
                sx={{
                  color: 'rgba(255, 255, 255, 0.6)',
                  '&:hover': {
                    color: '#FF0000',
                    transform: 'translateY(-2px)',
                  },
                  transition: 'all 0.3s ease',
                }}
              >
                <YouTube />
              </IconButton>
              <IconButton
                href="https://t.me/nautilusautomacao"
                target="_blank"
                rel="noopener noreferrer"
                sx={{
                  color: 'rgba(255, 255, 255, 0.6)',
                  '&:hover': {
                    color: '#0088cc',
                    transform: 'translateY(-2px)',
                  },
                  transition: 'all 0.3s ease',
                }}
              >
                <TelegramIcon />
              </IconButton>
            </Box>
          </Box>
        </Paper>
      </Container>

      {/* Modal de Opções de Pagamento */}
      <Dialog
        open={showPaymentModal}
        onClose={handleClosePaymentModal}
        maxWidth="sm"
        fullWidth
        PaperProps={{
          sx: {
            background: 'hsla(0, 0.00%, 0.00%, 0.93) !important',
            border: '2px solid #C0C0C0',
            borderRadius: 4,
            boxShadow: '0 4px 32px 0 rgba(192,192,192,0.12)',
            color: '#C0C0C0',
            p: 3
          }
        }}
      >
        <DialogTitle sx={{ 
          display: 'flex', 
          justifyContent: 'space-between', 
          alignItems: 'center',
          borderBottom: '1px solid rgba(0, 212, 255, 0.1)',
          pb: 2,
          fontWeight: 600,
          color: '#00d4ff',
          fontSize: '1.3rem'
        }}>
          Planos de Assinatura
          <IconButton onClick={handleClosePaymentModal} sx={{ color: 'white' }}>
            <Close />
          </IconButton>
        </DialogTitle>
        <DialogContent sx={{ py: 4, px: 5, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 2.5 }}>
          <Button
            variant="contained"
            onClick={() => handlePaymentClick('https://checkout.grupobigwhale.com/b/14A00l6Ei05a4o04W7gnK02')}
            className="button-plano"
            sx={{
              width: '100%',
              maxWidth: 400,
              py: 2.5,
              mt: 3,
              mb: 2.5,
              fontSize: '1.3rem',
              fontWeight: 800,
              letterSpacing: 0.5,
              transition: 'all 0.3s',
            }}
          >
            Assinatura Mensal
          </Button>
          <Button
            variant="contained"
            onClick={() => handlePaymentClick('https://checkout.grupobigwhale.com/b/4gM14pfaO6tyg6IfALgnK03')}
            className="button-plano"
            sx={{
              width: '100%',
              maxWidth: 400,
              py: 2.5,
              fontSize: '1.3rem',
              fontWeight: 800,
              letterSpacing: 0.5,
              transition: 'all 0.3s',
            }}
          >
            Assinatura Anual
          </Button>
          <Typography variant="body2" sx={{ color: 'rgba(255,255,255,0.7)', mt: 2, fontStyle: 'italic' }}>
            (Modo sem cobrança de comissão)
          </Typography>
        </DialogContent>
      </Dialog>

      {/* Modal de Convite */}
      <Dialog
        open={showInviteModal}
        onClose={() => {
          setInviteCode('');
          setInviteError('');
          setInviteSuccess(false);
          handleCloseInviteModal();
        }}
        maxWidth="xs"
        fullWidth
        PaperProps={{
          sx: {
            background: 'hsla(0, 0.00%, 0.00%, 0.93) !important',
            border: '2px solid #C0C0C0',
            borderRadius: 4,
            boxShadow: '0 4px 32px 0 rgba(192,192,192,0.12)',
            color: '#C0C0C0',
            p: 3
          }
        }}
      >
        <DialogTitle sx={{ 
          display: 'flex', 
          justifyContent: 'space-between', 
          alignItems: 'center',
          borderBottom: '1px solid rgba(0, 212, 255, 0.1)',
          pb: 2,
          fontWeight: 600,
          color: '#00d4ff',
          fontSize: '1.3rem'
        }}>
          Registro por Convite
          <IconButton onClick={handleCloseInviteModal} sx={{ color: 'white' }}>
            <Close />
          </IconButton>
        </DialogTitle>
        <DialogContent sx={{ py: 3, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 2 }}>
          <Typography variant="body1" sx={{ color: 'rgba(255,255,255,0.85)', mb: 2, textAlign: 'center' }}>
            Digite o código de convite para liberar o cadastro:
          </Typography>
          <TextField
            label="Código de Convite"
            variant="outlined"
            value={inviteCode}
            onChange={e => setInviteCode(e.target.value)}
            fullWidth
            sx={{
              input: { color: 'white' },
              label: { color: 'rgba(255,255,255,0.7)' },
              mb: 1,
              '& .MuiOutlinedInput-root': {
                backgroundColor: 'rgba(0, 0, 0, 0.2)',
                borderRadius: 2,
                '& fieldset': {
                  borderColor: 'rgba(0, 212, 255, 0.3)',
                },
                '&:hover fieldset': {
                  borderColor: 'rgba(0, 212, 255, 0.5)',
                },
                '&.Mui-focused fieldset': {
                  borderColor: '#00d4ff',
                  boxShadow: '0 0 0 2px rgba(0, 212, 255, 0.1)',
                },
              },
            }}
            InputLabelProps={{ style: { color: 'rgba(255,255,255,0.7)' } }}
            autoFocus
            onKeyDown={e => { if (e.key === 'Enter') handleValidateInvite(); }}
            disabled={inviteSuccess}
          />
          {inviteError && (
            <Typography variant="body2" sx={{ color: '#ff6464', mb: 1 }}>{inviteError}</Typography>
          )}
          {inviteSuccess ? (
            <Typography variant="h6" sx={{ color: '#00ff64', mt: 2, textAlign: 'center' }}>
              Código válido! Redirecionando...
            </Typography>
          ) : (
            <Button
              variant="contained"
              onClick={handleValidateInvite}
              className="button-validar-codigo"
              sx={{ mt: 2 }}
              fullWidth
            >
              Validar Código
            </Button>
          )}
          <Typography variant="body2" sx={{ color: 'rgba(255,255,255,0.7)', textAlign: 'center', mt: 2 }}>
            O código de convite é pessoal e intransferível. Após validar, siga as regras já exibidas na tela de registro.
          </Typography>
        </DialogContent>
      </Dialog>
    </Box>
  );
};

export default Login;
